"""
MKT Christ Commentary — Daniel chapters 6–8
Run: python3 scripts/zc-christ-daniel-6-8.py

Key decisions:
- Daniel in the lions' den (ch 6) is a sustained type of Christ's passion and resurrection:
  sinless life (v4-5), sealed tomb (v17), resurrection at dawn (v19-23), accusers judged (v24).
- Daniel 7 is the book's christological apex: the Son of Man vision (v13, already present)
  interpreted in light of Jesus's explicit self-application (Matt 26:64; Mark 14:62).
- The Ancient of Days (7:9-10) is treated as a revelation of God, not a christophany, as
  in the NT the Son of Man approaches the Ancient of Days as a distinct figure (v13).
- Dan 8: Antiochus IV (the small horn) = shadow/type of the Antichrist figure resolved in
  Christ; Gabriel = angel who announces the Messiah; "broken without human hand" = divine
  agency only, fulfilled in Rev 19:20 and Dan 2:34 stone.
- Directness levels: v13 (ch7) = direct (already written); ch 6 entombment/resurrection
  sequence = type; ch 7 Son of Man material = direct; ch 8 Gabriel/small horn = shadow/allusion.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DANIEL = {
  "6": {
    "1": '<p>A theme: Darius reorganizes empire into 120 provinces under three administrators, with Daniel first among them. God repeatedly places his servants in positions of unlikely authority in hostile empires — Joseph over Egypt, Nehemiah over Jerusalem, Esther over Persia — as a pattern fulfilled when the Son of Man is given "dominion and glory and a kingdom" over all peoples (Dan 7:14). Daniel\'s earthly authority is a shadow of Christ\'s cosmic appointment.</p>',
    "2": '<p>A theme: Daniel is "first" among the administrators, distinguished not by ethnic or political origin but by the excellence of his character and spirit (v.3). The elevation of the lowly exile to first position is a consistent OT pattern (Joseph, Moses, David) that reaches its definitive expression in the resurrection: the one rejected and entombed is raised to be "first" over all things (Col 1:18, "that in everything he might be preeminent").</p>',
    "3": '<p>A theme: "An excellent spirit was in him" — Daniel\'s distinguishing quality is spiritual, not political. The Spirit\'s presence in a servant of God, marking him out for unique service, is the pattern fulfilled when the Spirit descends on Jesus at his baptism (Matt 3:16-17) and the Father declares him the beloved Son. Daniel\'s excellent spirit points to the one who is filled with the Spirit without measure (John 3:34).</p>',
    "4": '<p>A type: The administrators and satraps "could find no grounds for complaint" against Daniel, "because he was faithful, and no error or fault was found in him." This is the OT type of the trial of Jesus: Pilate declares "I find no fault in this man" (Luke 23:4,14), Herod sends him back with the same verdict, Judas confesses "I have sinned by betraying innocent blood" (Matt 27:4). Daniel\'s blamelessness before his accusers prefigures Christ\'s sinlessness under hostile scrutiny.</p>',
    "5": '<p>A type: "We will find no grounds for complaint against Daniel unless we find it in connection with the law of his God." The accusers cannot defeat Daniel in any arena except the very thing that defines him — his devotion to God. The Pharisees\' strategy against Jesus follows the same path: unable to discredit him on moral grounds, they charge him with blasphemy — attacking his claim to be the Son of God (Matt 26:65). In both cases, the accusation against the faithful one is framed in terms of his identity before God.</p>',
    "6": '<p>A shadow: The conspiracy of court officials to trap Daniel in an irrevocable legal snare mirrors the Sanhedrin\'s strategy of using Roman legal authority to make Jesus\'s execution irreversible (John 18:31 — "we are not permitted to put anyone to death"). The trap is legal: once sealed, even the sympathetic ruler cannot undo it (v.14-15), just as Pilate\'s verdict, once given, cannot be recalled.</p>',
    "7": '<p>A shadow: The decree prohibiting prayer to any god except the king for thirty days — a temporary absolute ban on approaching any authority but the supreme human one — is a shadow of every system that sets human power against access to God. Christ\'s cross and resurrection break the ultimate form of that ban, reopening the way to the Father (Heb 10:19-20: "by the new and living way that he opened for us through the curtain").</p>',
    "8": '<p>A shadow: The decree, once signed, cannot be changed "in keeping with the law of the Medes and Persians, which cannot be revoked." The irrevocable human decree that condemns the innocent is the structural analogy to the immutable divine law that requires death for sin (Rom 6:23). In both cases, the faithful one enters the death that the law requires. The difference: in Daniel, the law is unjust; in Christ, the law is just but satisfied in his person.</p>',
    "9": '<p>A shadow: King Darius signs the decree — personally sympathetic to Daniel but legally bound to an agreement he cannot undo. Pilate acts under the same structural pressure: personally convinced of Jesus\'s innocence (Matt 27:24) but yielding to the crowd. The sympathetic-ruler-who-cannot-prevent-the-execution is a recurring type in the passion narrative.</p>',
    "10": '<p>A type: Daniel, learning that the decree is signed, goes home and prays openly, windows toward Jerusalem, three times a day as before. He does not conceal or alter his practice when it becomes illegal; he continues in faithful prayer knowing the cost. This is the pattern of Gethsemane: Jesus, knowing what is coming, prays toward the Father three times (Matt 26:36-44). The faithful servant prays rather than retreats when the hour of testing arrives.</p>',
    "11": '<p>A theme: The men find Daniel "praying and making supplication before his God" — his guilt consists entirely of faithful prayer. The Son of God\'s "guilt" at his trial also consists entirely of who he is before God: the high priest tears his robes not over a crime but over a claim (Matt 26:65). In both trials, being what the faithful one truly is constitutes the "offense" in the eyes of the accusers.</p>',
    "12": '<p>A shadow: The accusers quote the king\'s own decree to trap him — the legal mechanism is activated by those who engineered it. The chief priests similarly activate Roman law against Jesus: "If you release this man, you are no friend of Caesar" (John 19:12). In each case, the human legal trap is the instrument; the faithful one enters it willingly.</p>',
    "13": '<p>A shadow: "Daniel, who is one of the exiles from Judah, pays no attention to you, O king." The charge emphasizes Daniel\'s identity as a Jewish exile — an outsider whose loyalty to his God overrides loyalty to empire. Jesus is similarly identified by his opponents in terms of regional and ethnic origin (cf. John 7:52). The outsider status of the faithful servant is part of the shame the accusers intend to amplify.</p>',
    "14": '<p>A type: "When the king heard these words, he was greatly distressed and set his heart on Daniel to deliver him." Darius labors until sundown trying to find a way to rescue Daniel from the legal trap. This is a type of God\'s heart toward his Son — and toward every believer condemned by the law. The one who seeks with everything to deliver the condemned one is the image fulfilled in God sending his Son as the rescuer (John 3:17: "God did not send his Son to condemn the world but to save the world through him").</p>',
    "15": '<p>A shadow: "Know, O king, that it is a law of the Medes and Persians that no injunction or ordinance that the king issues can be changed." The irrevocable death sentence over an innocent man is the shadow of the sentence of death that stands over humanity. The law cannot be changed (Rom 7:12 — the law is holy, righteous, and good); the innocent one must enter the sentence for it to be satisfied and transcended.</p>',
    "16": '<p>A type: "So the king gave the command, and they brought Daniel and threw him into the den of lions." The king speaks words of hope over Daniel — "your God, whom you serve continually, he will deliver you" — before the faithful servant is cast into the place of death. The parallel to the crucifixion is direct: "He trusts in God; let God deliver him now if he wants him" (Matt 27:43, citing Ps 22:8). The promise of rescue is spoken over the faithful servant as he enters the tomb.</p>',
    "17": '<p>A direct type: "A stone was brought and laid over the mouth of the den, and the king sealed it with his own signet ring and with the signet rings of his nobles." Matthew 27:60,66 records that a large stone was rolled against the door of the tomb and the tomb was sealed with a guard set. The correspondence is structural and unmistakable: the faithful innocent one, sealed in a death chamber by official authority, is the pattern Daniel enacts and Christ fulfills.</p>',
    "18": '<p>A shadow: "The king returned to his palace and spent the night fasting; no entertainments were brought before him, and sleep fled from him." The sleepless, fasting, anguished ruler waiting through the night images the vigil of all who wait for the faithful one to emerge from death. The women who wait at the tomb (Luke 23:55-56; 24:1) and the disciples behind locked doors (John 20:19) enact the same night watch.</p>',
    "19": '<p>A direct type: "Then at the first light of dawn the king arose and hurried to the den of lions." The resurrection is announced at dawn. All four Gospels report the women arriving at the tomb "at the first light of dawn" (Matt 28:1; Mark 16:2; Luke 24:1; John 20:1). The dawn resurrection is not accidental in either narrative; it is the structure of the type and its fulfillment: the night of death ends, and the first light reveals the vindicated servant alive.</p>',
    "20": '<p>A type: "He called to Daniel in an anguished voice, \'O Daniel, servant of the living God, has your God, whom you serve continually, been able to deliver you from the lions?\'" The question at the tomb — has death been defeated? — is the question that drives the entire resurrection narrative. Mary Magdalene asks the same question in different form: "Where have they laid him?" (John 20:13). In both cases, the answer will be life where death was expected.</p>',
    "21": '<p>A type: Daniel answers — "O king, live forever!" — the formal greeting spoken by one who should be dead. The risen Christ\'s first words to the women (Matt 28:9; John 20:16) carry the same structural weight: the one who should not be speaking, speaks. The emergence of voice from the place of expected silence is the signature of resurrection.</p>',
    "22": '<p>A direct type: "My God sent his angel and shut the lions\' mouths, and they have not harmed me, because I was found blameless before him, and also before you, O king, I have done no harm." Three elements: divine rescue, blamelessness certified, vindication before God and human authority. Romans 4:25 states that Christ "was raised for our justification" — his resurrection is the divine declaration of blamelessness, the ultimate vindication of the one the accusers condemned.</p>',
    "23": '<p>A type: "Daniel was lifted out of the den. No wound was found on him, because he had trusted in his God." The faithful servant, lifted from the place of death, shows no wound from the ordeal. Christ\'s resurrection body retains the wounds (John 20:27) — but they are wounds of glory, not of continuing injury. The "no wound found" in Daniel is the type; the "wounds present but transformed" in Christ surpasses the type.</p>',
    "24": '<p>A shadow: The accusers who condemned Daniel are thrown into the den and immediately destroyed. The shadow of eschatological reversal — persecutors facing the death they designed for the faithful — recurs in Revelation\'s judgment oracles (Rev 19:20; 20:10-15). Those who condemned Christ will face the same reversal before the Son of Man at the last judgment (Matt 25:41; John 5:29).</p>',
    "25": '<p>A theme: Darius\'s decree to all peoples, nations, and languages echoes Dan 7:14 where the same formula describes the scope of the Son of Man\'s dominion. The pagan king who witnessed God\'s power issues a universal proclamation — anticipating the Great Commission (Matt 28:18-20): the risen Christ, given "all authority in heaven and on earth," sends his servants to "all nations."</p>',
    "26": '<p>A revelation of God: "He is the living God, enduring forever. His kingdom will never be destroyed, and his dominion has no end." The title "living God" (<em>elah chayyah</em>) is the decisive contrast with the lions and the idol-gods of empire. Jesus identifies himself with this living God: "I am the resurrection and the life" (John 11:25); "I am the way, the truth, and the life" (John 14:6).</p>',
    "27": '<p>A revelation of God: "He delivers and rescues; he works signs and wonders in heaven and on earth — he who delivered Daniel from the power of the lions." The three verbs — delivers, rescues, works wonders — are the pattern of God\'s saving acts from the exodus onward. Jesus\'s ministry of healing, exorcism, and raising the dead embodies these same verbs (Matt 4:23-24; Luke 7:22). The God who delivered Daniel is the God who raised Jesus from the dead (Acts 2:24).</p>',
    "28": '<p>A theme: "Daniel prospered during the reign of Darius and during the reign of Cyrus the Persian." The faithful servant survives the transition between empires. Christ\'s reign outlasts every empire — Roman, medieval, modern. The book\'s final word on Daniel is prosperity and advancement: the faithful servant advances as kingdoms come and go. The risen Christ is Lord over every successor to every Babylon (Rev 17:14).</p>'
  },
  "7": {
    "1": '<p>A shadow: Daniel 7 is the christological apex of the OT — the chapter that most directly names the one who will receive universal, eternal dominion. The setting: the first year of Belshazzar, before the fall of Babylon. The vision comes to an exile through dream — the medium through which God addressed Joseph. The humility of the recipient frames the magnitude of the revelation.</p>',
    "2": '<p>A shadow: "Four winds of heaven stirring up the great sea." The sea in prophetic literature is the realm of chaos and death (Isa 57:20; Rev 21:1 "there was no more sea"). The four winds driving the chaos are the forces of historical turbulence from which human empire rises. The Son of Man comes "with the clouds of heaven" (v.13) — from above the chaos. His origin contrasts with the beasts\' from the beginning.</p>',
    "3": '<p>A shadow: "Four great beasts came up from the sea, each different from the others." The four beasts are the succession of world empires — the same kingdoms as the statue of chapter 2, seen from below (as beasts) rather than from above (as precious metals). The progression of empires is the problem the Son of Man\'s kingdom solves. Each beast rises, dominates, and is superseded; the Son of Man\'s kingdom alone is "everlasting" (v.14).</p>',
    "4": '<p>A shadow: The first beast — lion with eagle\'s wings, given a human mind — is Babylon. Its humanization anticipates Nebuchadnezzar\'s own in ch.4. Empire that operates on purely bestial terms eventually receives enough human dignity to recognize its limits. The trajectory is toward acknowledgment of the Most High — which is also the trajectory of all creation toward Christ (Phil 2:10-11).</p>',
    "5": '<p>A shadow: The second beast — bear raised on one side, three ribs in its mouth, "devour much flesh" — is Medo-Persia. The progressive escalation of destructive power through the beasts is the OT\'s honest assessment of what human empire does — the problem that Christ\'s kingdom displaces (1 Cor 15:24-25: "then comes the end, when he delivers the kingdom to God after destroying every rule and authority and power").</p>',
    "6": '<p>A shadow: The leopard with four wings — Greece and Alexander\'s rapid conquest — moves with supernatural speed. The four heads represent the division of Alexander\'s empire after his death. The pattern: rapid rise, fragmentation, dissolution. Every human empire that seems to achieve universality splinters. The contrast with the Son of Man\'s undivided, eternal dominion (v.14) is deliberate.</p>',
    "7": '<p>A shadow: The fourth beast — "terrifying, dreadful, and overpowering... different from all the beasts that preceded it, and it had ten horns" — deliberately transcends any single historical empire. It represents the final form of human power organized against God. The NT uses this imagery for the Roman imperial cult (Rev 13:1-8); its "ten horns" become the background for John\'s beast.</p>',
    "8": '<p>A shadow: The little horn — speaking boastful words, with "eyes like human eyes and a mouth speaking great things" — is the prototype of Paul\'s "man of lawlessness" (2 Thess 2:3-4) and John\'s "beast" (Rev 13:5-6). Christ\'s return is specifically presented as the termination of this figure (2 Thess 2:8: "the Lord Jesus will kill him with the breath of his mouth").</p>',
    "9": '<p>A revelation of God: "Thrones were set in place and the Ancient of Days took his seat. His clothing was white as snow and the hair of his head like pure wool. His throne was flaming fire and its wheels were blazing fire." The Ancient of Days is the eternal Judge. John\'s vision of the risen Christ in Rev 1:14 gives him the same white hair, linking the glorified Christ to this imagery — but the scene of v.9 and v.13 distinguishes the Son of Man approaching the Ancient of Days. Father and Son are both present; the scene is Trinitarian in structure even in its OT form.</p>',
    "10": '<p>A theme: "A river of fire flowed out from before him; thousands upon thousands attended him, and myriads upon myriads stood before him; the court sat in judgment and the books were opened." The heavenly court scene is the template for the great white throne judgment (Rev 20:11-15) and the scene of Heb 12:22-24 (the assembly of the firstborn enrolled in heaven). Christ will preside at this judgment as both Son of Man and righteous Judge (John 5:27: "he has given him authority to execute judgment because he is the Son of Man").</p>',
    "11": '<p>A shadow: "Then the beast was killed and its body destroyed and given over to be burned with fire." The destruction of the fourth beast in response to the boastful horn anticipates Rev 19:20 (the beast and false prophet thrown into the lake of fire). Christ\'s return consigns the final empire to permanent destruction — the fire that kills the beast is the fire that precedes the Ancient of Days (v.10).</p>',
    "12": '<p>A shadow: "As for the rest of the beasts, their dominion was taken away, but their lives were prolonged for a season and a time." Previous empires stripped of ultimate power but permitted to continue — Babylon (Nebuchadnezzar restored), Persia (Cyrus as God\'s anointed, Isa 45:1), Greece (preserved as culture). This is the pattern of common grace: empires under sovereign providence that awaits the full disclosure of the Son of Man\'s kingdom.</p>',
    "14": '<p>A direct fulfillment: "He was given authority, glory, and sovereign power. All peoples, nations, and languages worshiped him. His dominion is an everlasting dominion that will not pass away, and his kingdom is one that will never be destroyed." This is the explicit NT claim for the resurrected Christ (Matt 28:18: "All authority in heaven and on earth has been given to me"; Phil 2:9-11: "every knee should bow... to the glory of God the Father"). Jesus applied Dan 7:13-14 to himself before the high priest (Matt 26:64). The "all peoples, nations, and languages" formula used of every empire in Daniel here transfers to the Son of Man as its only legitimate possessor.</p>',
    "15": '<p>A theme: "My spirit was troubled within me and the visions of my head dismayed me." The prophet\'s response to overwhelming revelation — trembling, confusion, needing help to stand — is the pattern of encounter with divine glory (Isa 6:5; Ezek 1:28; Rev 1:17). Daniel\'s bewilderment at a vision he cannot fully understand mirrors the disciples\' bewilderment at the transfiguration and resurrection appearances.</p>',
    "16": '<p>A theme: Daniel approaches one of those standing nearby and asks for the true meaning. The desire to understand what the vision truly signifies is the posture of prophetic humility. The Spirit\'s role in the NT is to interpret what Christ has accomplished (John 16:13-14: "he will take what is mine and declare it to you") — the same movement of heaven providing interpretation to the overwhelmed human recipient.</p>',
    "17": '<p>A shadow: "These four great beasts are four kings who will rise from the earth." Their origin "from the earth" contrasts with the Son of Man\'s origin "with the clouds of heaven" (v.13). The christological point: the Son of Man is the heavenly answer to the earthly problem. He does not arise from the sea of chaos; he comes from above it.</p>',
    "18": '<p>A direct promise: "But the holy ones of the Most High will receive the kingdom and will possess it forever — yes, forever and ever." The saints\' inheritance of the kingdom is the corollary of the Son of Man\'s reception of dominion. In Christ, believers are made co-heirs (Rom 8:17); in Christ, the church will reign with him (Rev 2:26-27; 20:4; 1 Cor 6:2-3). Daniel 7:18 is the OT foundation for the NT\'s theology of shared eschatological inheritance.</p>',
    "19": '<p>A shadow: Daniel asks about the fourth beast — "the truth about" it. The persistent desire to understand the mystery of the final empire and its destruction is the posture of the church under persecution. NT epistles repeatedly address communities suffering under Rome\'s fourth-beast power, pointing them to the certainty of the horn\'s destruction (Rev 13:10; 2 Thess 1:5-10).</p>',
    "20": '<p>A shadow: The little horn that defeats others, "which had eyes and a mouth that spoke boastfully and which seemed greater in appearance than its companions." The self-exalting king who defeats rivals is applied in the NT to both the Roman imperial cult (Rev 13:5-6) and the "man of lawlessness" (2 Thess 2:4). Christ is the one who unmasks and ends this entire category of power.</p>',
    "21": '<p>A shadow: "This horn was waging war against the holy ones and prevailing over them." The temporary apparent victory of the persecutor over the saints is the pattern addressed throughout the NT (Rev 12:17; 13:7: "the beast was allowed to make war on the saints and to conquer them"). The tribulation is real, and for a time the enemy prevails. But v.22 is the answer: "until the Ancient of Days came."</p>',
    "22": '<p>A direct promise: "Until the Ancient of Days came and pronounced judgment in favor of the holy ones of the Most High, and the time came when the holy ones possessed the kingdom." The entire period of the little horn\'s apparent victory is bounded by the single word "until." The Ancient of Days arrives; judgment is pronounced in favor of the saints. This is the plot of Revelation: the saints under persecution, the Lamb returns, all things are made new.</p>',
    "23": '<p>A shadow: The fourth beast as a fourth kingdom that "will devour the whole earth and trample it down and crush it." The comprehensive destructive ambition of the final empire is the backdrop against which the Son of Man\'s universal, constructive dominion is displayed. Where the beast devours, the Son of Man gives life; where the beast crushes, the Son of Man lifts up.</p>',
    "24": '<p>A shadow: The ten horns and the different king who subdues three and sets himself against the Most High. The escalating self-deification of the final ruler is the trajectory Paul traces in 2 Thess 2:3-10: the son of destruction "opposes and exalts himself against every so-called god or object of worship, so that he takes his seat in the temple of God, proclaiming himself to be God."</p>',
    "25": '<p>A direct shadow: "He will speak words against the Most High and will wear down the holy ones of the Most High. He will try to change the sacred seasons and the law; and they will be handed over to him for a time, times, and half a time." Revelation 12:14 quotes "a time, times, and half a time" directly as the duration of the dragon\'s persecution. The fixed duration is the NT\'s assurance that the persecution is bounded: it will end precisely when God decrees.</p>',
    "26": '<p>A direct promise: "But the court will sit in judgment, and his dominion will be taken away — utterly consumed and destroyed forever." The final destruction of the anti-kingdom is absolute and permanent. Paul\'s "utterly consumed and destroyed" in 2 Thess 2:8 echoes this verse directly. Christ\'s return is not merely a defeat of the enemy but a termination of the entire system of opposition to God.</p>',
    "27": '<p>A direct fulfillment: "The sovereignty, power, and greatness of all the kingdoms under heaven will be handed over to the people of the Most High. His kingdom will be an everlasting kingdom, and all rulers will worship and obey him." Revelation 11:15 presents this as accomplished: "The kingdom of the world has become the kingdom of our Lord and of his Christ, and he will reign forever and ever." Daniel 7:27 is the OT promise; Revelation 11:15 is the eschatological announcement of its fulfillment in Christ.</p>',
    "28": '<p>A theme: "This is the end of the account. As for me, Daniel, my thoughts greatly troubled me and my color changed, but I kept the matter in my heart." The prophet who has received the definitive vision of the Son of Man\'s kingdom keeps it in his heart — unable yet to speak it fully. Revelation 22:10 directly inverts Daniel\'s sealing command: "Do not seal up the words of the prophecy of this book, for the time is near." What Daniel must keep sealed, the church proclaims openly — because the fulfillment has come in Christ.</p>'
  },
  "8": {
    "1": '<p>A theme: "In the third year of King Belshazzar\'s reign, a vision appeared to me, Daniel, after the one that had appeared to me previously." The sequence of visions — each building on the last — is the structure of progressive revelation. Daniel 8 narrows the focus of Daniel 7\'s universal scope to a specific historical sequence (Media-Persia to Greece) while maintaining the pattern of divine sovereignty over empires. The narrowing focus mirrors the NT\'s movement from universal redemptive history to its particular fulfillment in one person.</p>',
    "2": '<p>A theme: Daniel is transported in the vision to Susa — the future capital of Persia, the setting of Esther and Nehemiah. The vision takes place in the heart of the very empire it predicts, before that empire\'s rise. God\'s foreknowledge places his prophet in the future location before the future arrives — a shadow of the Word being present at creation before the creation he will redeem (John 1:1-3).</p>',
    "3": '<p>A shadow: The ram with two unequal horns — Media and Persia, with Persia rising higher — is identified by Gabriel in v.20. God\'s precise sovereignty over the mechanics of empire succession reflects the same sovereignty that will, in the fullness of time, send his Son "born of a woman, born under the law" (Gal 4:4) into a particular political and cultural moment prepared by this succession.</p>',
    "4": '<p>A shadow: The ram charging in every direction, no animal able to stand against him, doing as he pleases. The grammar of total domination echoes the fourth beast\'s "no one could stand before him" (7:7). The repetition establishes the pattern: every empire that achieves this kind of absolute power will be overthrown, because absolute power belongs to God alone.</p>',
    "5": '<p>A shadow: The male goat from the west "across the whole face of the earth, without touching the ground" — Alexander the Great\'s rapid conquest. Gabriel identifies the goat as Greece (v.21). Speed without contact with earth images a power that cannot be sustained. Every human empire that seems to achieve universality splinters; the contrast with the Son of Man\'s undivided eternal dominion is deliberate.</p>',
    "6": '<p>A shadow: The goat charges the ram "with furious force" — the clash of empires as a cosmic conflict between massive animals. The spectacle of world-historical battles is, from the prophetic perspective, a visible drama enacting what God has already decreed. The NT equivalent: the cross and resurrection appear to be a clash between Rome and one Galilean rabbi, but the cosmic reality is the defeat of all principalities and powers (Col 2:15).</p>',
    "7": '<p>A shadow: The ram thrown to the ground, trampled, none to rescue him — the total defeat of Medo-Persia. The phrase "none to rescue him" tracks the reversal of v.4 where none could rescue from the ram\'s power. Every power that sets itself above God\'s appointed order will experience this reversal. The ultimate reversal is reserved for the last enemy, death (1 Cor 15:26).</p>',
    "8": '<p>A shadow: "The male goat became exceedingly great, but at the height of his power the great horn was broken off." Alexander died at 32 at the height of his power. Four kingdoms replaced the one — smaller, less powerful. Every fragment of fallen greatness is less than the original; only the kingdom of the Son of Man grows rather than fragments (Dan 2:35: the stone becomes a great mountain filling the whole earth).</p>',
    "9": '<p>A shadow: "Out of one of these four horns came another horn, which started small but grew exceedingly great toward the south, toward the east, and toward the glorious land." The small horn is Antiochus IV Epiphanes (175-164 BCE), who desecrated the Jerusalem temple in 167 BCE. He is the type of the final Antichrist figure — the NT\'s "man of lawlessness" (2 Thess 2:3) and "beast" (Rev 13) — the antitype of whom only Christ\'s return resolves.</p>',
    "10": '<p>A shadow: "It grew great, even to the host of heaven, and some of the host of heaven and some of the stars it hurled to the ground and trampled on them." The small horn\'s assault on heaven — escalating from earthly to cosmic opposition to God. Antiochus IV claimed the divine title "Epiphanes" (God Manifest). This pattern of human power claiming divine status culminates in the Antichrist who "proclaims himself to be God" (2 Thess 2:4).</p>',
    "11": '<p>A direct fulfillment: "It magnified itself even against the Prince of the host. The regular burnt offering was taken away, and the site of his sanctuary was overthrown." Jesus explicitly cites this passage (Matt 24:15: "the abomination of desolation... let the reader understand") as pointing to a future fulfillment beyond Antiochus. The removal of the regular offering is the type; Christ\'s once-for-all offering (Heb 10:12-14) is the answer to the desecration — the sanctuary not merely restored but transcended.</p>',
    "12": '<p>A shadow: "Truth was cast to the ground, and the horn acted and prospered." The casting of truth to the ground is the central act of sacrilege. The NT counterpart is the rejection of the one who is "the way, the truth, and the life" (John 14:6) — the one who embodies truth is cast to the ground at the crucifixion. But truth cast to the ground rises.</p>',
    "13": '<p>A theme: "How long will the vision last — the regular offering taken away and the transgression that devastates, giving over the sanctuary and the host to be trampled?" The "how long?" question is the question of every persecuted community (Rev 6:10: "How long, O Lord?"). The answer in v.14 provides a measured limit; the NT answer is the return of Christ. Every "how long?" in Scripture is answered ultimately by the same event.</p>',
    "14": '<p>A shadow: "For 2,300 evenings and mornings; then the sanctuary will be restored to its rightful state." Historically, Judas Maccabeus rededicated the temple in 164 BCE (Hanukkah). But the deeper restoration of the sanctuary is Christ himself: "Destroy this temple, and in three days I will raise it up" (John 2:19-21). The desecrated and restored temple is the type; Christ\'s death and resurrection is the antitype — and the church, his body, is the permanent temple (1 Cor 3:16; Eph 2:21-22).</p>',
    "15": '<p>A theme: "I was seeking to understand" — Daniel actively pursues the meaning of the vision. The posture of seeking understanding from heaven is the prophetic disposition the NT applies to the entire OT: "the prophets... searched and inquired carefully, inquiring what person or time the Spirit of Christ in them was indicating" (1 Pet 1:10-11). The prophets who gave the Scripture did not fully understand what they wrote.</p>',
    "16": '<p>A type: Gabriel is named for the first time in Scripture in this verse — the only named angel in the OT alongside Michael. He is commissioned to help Daniel understand the vision. The same Gabriel appears in Luke 1:19 (to Zechariah) and 1:26 (to Mary), announcing the Messiah whose birth fulfills Daniel\'s visions. The angel who interprets the vision of empires is the angel who announces the king who will end them all.</p>',
    "17": '<p>A shadow: "Understand, son of man (<em>ben-adam</em>), that the vision is for the time of the end." Gabriel addresses Daniel as <em>ben-adam</em> (mortal human), the same term used throughout Ezekiel. The contrast with Dan 7:13 is deliberate: Daniel the prophet is addressed as "son of man" (mortal), while the figure in 7:13 who receives the kingdom is the Son of Man (the divine-human ruler). The one who receives revelation from heaven is distinct from the one who comes from heaven.</p>',
    "18": '<p>A type: "While he was speaking to me, I fell into a deep sleep with my face to the ground. But he touched me and raised me to my feet." The pattern — overwhelming divine presence, prostration, touch, raising — recurs at the Transfiguration (Matt 17:6-7: disciples fell on their faces; Jesus touched them and said "Rise") and in Revelation (1:17: John fell as dead; he placed his right hand on him). The gesture of the angel raising Daniel is a type of the resurrection touch of Christ.</p>',
    "19": '<p>A shadow: "I am going to tell you what will take place in the latter period of the wrath, for it refers to the appointed time of the end." The "appointed time" (<em>moed</em>) fixed by divine decree is the category Paul uses in Gal 4:4 ("the fullness of time") and Eph 1:10 ("a plan for the fullness of time"). History moves toward a divinely fixed moment that arrived in the birth of Christ and will arrive finally in his return.</p>',
    "20": '<p>A theme: "The ram that you saw with two horns represents the kings of Media and Persia." The interpreted vision — empire as animal — reveals that what looks like unstoppable power is, in God\'s perspective, a categorized and predictable creature with a beginning and an end. The one who will "rule the nations with a rod of iron" (Rev 19:15) is the one before whom all the beast-kingdoms are already measured.</p>',
    "21": '<p>A theme: "The shaggy goat is the king of Greece, and the great horn between his eyes is the first king." The Greek empire that Daniel sees as a destructive goat is also the instrument through which Hebrew Scripture will be translated into Greek (the Septuagint, c.250 BCE) — the translation the NT authors will overwhelmingly quote. The empire identified as a beast is also the medium God uses to prepare the linguistic environment of the gospel.</p>',
    "22": '<p>A shadow: "The four horns that replaced the one that was broken represent four kingdoms that will arise from that nation, but without his power." The fragmented successor kingdoms divide and weaken Alexander\'s unified empire. The pattern — great unity broken into competing fragments — is the pattern of all human empire. The Son of Man\'s kingdom, by contrast, is given "everlasting dominion" that will not fragment (7:14).</p>',
    "23": '<p>A shadow: "At the end of their rule, when rebels have reached their limit, a king of bold face, skilled in intrigue, will arise." The phrase "when rebels have reached their limit" echoes Gen 15:16 ("when the iniquity of the Amorites reaches its full measure"). God\'s judgment operates on a measured pattern: sin is permitted to run its course to a defined limit before judgment falls. The "full measure" theology explains why God delays judgment and why that delay is not indefinite.</p>',
    "24": '<p>A shadow: "His power will be great, but not from his own strength." The Antichrist figure derives power from a supernatural source (Rev 13:2: "the dragon gave him his power, his throne, and great authority"). The contrast with Christ is direct: Christ\'s power is his own (John 10:18: "I have authority to lay it down and authority to take it up again"), while the counterfeit power is borrowed and temporary.</p>',
    "25": '<p>A shadow: "He will be broken without human hand." Only divine agency, not human power, can defeat the final enemy. This echoes Dan 2:34 (the stone cut without hands) and Rev 19:20 (the beast thrown into the lake of fire at Christ\'s return). Human armies cannot achieve what only God in Christ can. The entire book of Daniel has been building to this point: all empire ultimately yields to the one who acts without human hand.</p>',
    "26": '<p>A shadow: "Seal up the vision, for it concerns the distant future." The sealed vision is the sealed OT — comprehensible in outline, closed in full understanding until fulfillment. Revelation 22:10 directly inverts this: "Do not seal up the words of the prophecy of this book, for the time is near." What Daniel must seal, John must unseal — because the one who is the content of the vision has come. The age of sealed prophecy ended at the resurrection.</p>',
    "27": '<p>A theme: "I, Daniel, was exhausted and ill for several days. Then I got up and carried out the king\'s business, but I was appalled by the vision and did not understand it." The prophet receives revelation beyond his comprehension, rises from prostration, and returns to ordinary life — carrying the mystery he cannot yet fully articulate. The disciples carry the same burden after the resurrection: transformed by what they witnessed, not yet able to fully explain it (John 20:9), until the Spirit comes to make the vision clear (John 16:13).</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'daniel')
    merge_comm(existing, DANIEL)
    save_comm('mkt-christ', 'daniel', existing)
    print('Daniel 6-8 mkt-christ written.')

if __name__ == '__main__':
    main()
